// n8n Code Node - Transform Airtable data to array format with formatting

const items = $input.all();

const ids = [];
const values = [];

for (const item of items) {
  const data = item.json;
  ids.push(data.id);

  const fields = data.fields;

  const formattedValue = fields.Value.toFixed(2) + '€';
  const formattedUnits = fields.Units;
  const formattedVAT = fields.VAT + '%';
  const formattedRetention = fields.Retention === 0 ? '0%' : '-' + fields.Retention + '%';
  const formattedTotal = fields.Total.toFixed(2) + '€';

  const valueArray = [
    fields.Description,
    formattedValue,
    formattedUnits,
    formattedVAT,
    formattedRetention,
    formattedTotal
  ];

  values.push(valueArray);
}

return {
  json: {
    id: ids,
    values: {
      values: values
    }
  }
};

// n8n Code Node - Invoice Number Generator (JavaScript)

const currentYear = new Date().getFullYear();
const invoices = $input.all();

let maxNumber = 0;

for (const invoice of invoices) {
  const invoiceNum = invoice.json['Invoice #'];

  if (invoiceNum) {
    const parts = invoiceNum.split('-');

    if (parts.length === 2) {
      const year = parseInt(parts[0]);
      const number = parseInt(parts[1]);

      if (year === currentYear && !isNaN(number)) {
        maxNumber = Math.max(maxNumber, number);
      }
    }
  }
}

const nextNumber = maxNumber + 1;
const paddedNumber = nextNumber.toString().padStart(4, '0');
const nextInvoiceNumber = `${currentYear}-${paddedNumber}`;

return {
  json: {
    nextInvoiceNumber: nextInvoiceNumber,
    year: currentYear,
    sequenceNumber: nextNumber,
    lastInvoiceNumber: maxNumber > 0 ? `${currentYear}-${maxNumber.toString().padStart(4, '0')}` : 'None'
  }
};

